import type { CareerQuestion } from "./rrt-questions";

export const otaQuestionsBatch3: CareerQuestion[] = [
  { id: "ota-1116", stem: "An OTA is selecting a therapeutic exercise to improve grip strength. Which activity is MOST appropriate for a client at an intermediate level?", options: ["Squeezing a tennis ball", "Theraputty exercises with medium (red) resistance", "Maximum effort grip dynamometer testing", "Passive finger ROM only"], correctIndex: 1, rationale: "Medium resistance theraputty provides graded challenge for intermediate grip strengthening. Tennis balls provide inconsistent resistance, and maximal dynamometer effort is assessment, not exercise.", difficulty: 2, category: "Therapeutic Exercises", topic: "grip strengthening" },
  { id: "ota-1117", stem: "Which type of exercise uses body weight or resistance bands to improve functional strength?", options: ["Passive range of motion", "Active resistive exercise", "Assisted stretching", "Relaxation techniques"], correctIndex: 1, rationale: "Active resistive exercise uses external resistance (body weight, bands, weights, putty) to increase muscle strength. It requires voluntary contraction against resistance.", difficulty: 1, category: "Therapeutic Exercises", topic: "resistive exercise" },
  { id: "ota-1118", stem: "A client recovering from a wrist fracture has 30° of wrist extension. Normal is 70°. Which exercise approach is most appropriate?", options: ["No exercise until fully healed", "Active and active-assisted ROM exercises within pain-free range to restore extension", "Maximum resistance strengthening", "Only passive ROM performed by the OTA"], correctIndex: 1, rationale: "Active and AAROM within pain-free range promote healing, restore ROM, and prevent adhesions. The client performs movements actively with assistance as needed to regain extension.", difficulty: 1, category: "Therapeutic Exercises", topic: "ROM restoration" },
  { id: "ota-1119", stem: "What is the difference between isotonic and isometric exercises?", options: ["They are the same", "Isotonic involves joint movement against resistance; isometric involves muscle contraction without joint movement", "Isotonic is passive; isometric is active", "Isometric requires equipment; isotonic does not"], correctIndex: 1, rationale: "Isotonic exercise produces joint movement through muscle contraction against resistance (concentric/eccentric). Isometric exercise generates muscle force without joint movement (muscle length unchanged).", difficulty: 1, category: "Therapeutic Exercises", topic: "exercise types" },
  { id: "ota-1120", stem: "A client with a rotator cuff repair is cleared for AROM at 6 weeks. Which exercise sequence is appropriate?", options: ["Overhead press with heavy weights", "Pendulum exercises progressing to supine AROM, then standing AROM", "Plyometric throwing exercises", "Maximum effort isometrics immediately"], correctIndex: 1, rationale: "Post rotator cuff repair AROM progression: gravity-eliminated positions (pendulum, supine AROM) progress to antigravity positions (standing AROM) as tissue healing permits.", difficulty: 2, category: "Therapeutic Exercises", topic: "post-surgical exercise progression" },
  { id: "ota-1121", stem: "What is the primary purpose of tendon gliding exercises?", options: ["To increase cardiovascular endurance", "To maximize differential tendon excursion and prevent adhesions", "To strengthen core muscles", "To improve balance"], correctIndex: 1, rationale: "Tendon gliding exercises move flexor tendons through their full excursion within the tendon sheath, preventing adhesion formation after injury or surgery. Five positions: straight, hook, fist, table top, straight fist.", difficulty: 2, category: "Therapeutic Exercises", topic: "tendon exercises" },
  { id: "ota-1122", stem: "A client has shoulder flexion AROM of 90° and PROM of 160°. What does this discrepancy suggest?", options: ["Normal shoulder function", "Muscle weakness limiting active motion despite available passive range", "Joint contracture", "Complete frozen shoulder"], correctIndex: 1, rationale: "When PROM exceeds AROM significantly, the joint has available range but the muscles lack sufficient strength to move through full range. Strengthening exercises are indicated.", difficulty: 2, category: "Therapeutic Exercises", topic: "ROM assessment interpretation" },
  { id: "ota-1123", stem: "Which exercise type is best for improving endurance in a client returning to work after prolonged illness?", options: ["High-intensity short bursts only", "Low-to-moderate intensity, sustained aerobic exercise with gradual progression", "Maximum weight lifting", "Only stretching"], correctIndex: 1, rationale: "Endurance training uses low-to-moderate intensity sustained activity with gradual progression. This improves cardiovascular fitness and work tolerance for sustained occupational performance.", difficulty: 1, category: "Therapeutic Exercises", topic: "endurance training" },
  { id: "ota-1124", stem: "A client with elbow flexion contracture (lacks 30° of full extension) should receive which type of exercise?", options: ["Strengthening exercises for elbow flexors", "Prolonged low-load stretching into extension", "Strengthening exercises for wrist only", "No exercise — immobilize in current position"], correctIndex: 1, rationale: "Low-load prolonged stretching (LLPS) is the most effective approach for contractures. It provides sustained gentle force over time to remodel shortened tissues and restore ROM.", difficulty: 2, category: "Therapeutic Exercises", topic: "contracture management" },
  { id: "ota-1125", stem: "What is the correct sequence for a theraputty exercise program?", options: ["Start with firmest resistance and work down", "Start with softest (tan/yellow) and progress to firmer (red, green, blue) as strength improves", "Use only one resistance level throughout", "Alternate firm and soft randomly"], correctIndex: 1, rationale: "Theraputty progresses from extra-soft (tan) through soft (yellow), medium (red), firm (green), extra-firm (blue), to maximum (black). Progress as the client's strength improves.", difficulty: 1, category: "Therapeutic Exercises", topic: "putty exercise progression" },
  { id: "ota-1126", stem: "Which stretching technique uses a contract-relax sequence to improve flexibility?", options: ["Ballistic stretching", "Proprioceptive neuromuscular facilitation (PNF) stretching", "Static stretching only", "Vibration therapy"], correctIndex: 1, rationale: "PNF stretching uses contract-relax or hold-relax sequences: the client contracts the target muscle isometrically, relaxes, then the therapist applies a passive stretch into the new range.", difficulty: 2, category: "Therapeutic Exercises", topic: "flexibility techniques" },
  { id: "ota-1127", stem: "A client is performing wall push-ups as part of shoulder rehabilitation. This is an example of which type of exercise?", options: ["Open kinetic chain", "Closed kinetic chain", "Passive range of motion", "Isokinetic exercise"], correctIndex: 1, rationale: "Wall push-ups are closed kinetic chain exercises (hands fixed on wall). CKC exercises provide joint compression, co-contraction, and proprioceptive feedback beneficial for shoulder stability.", difficulty: 1, category: "Therapeutic Exercises", topic: "kinetic chain exercises" },
  { id: "ota-1128", stem: "What is the recommended duration for holding a static stretch to achieve optimal flexibility gains?", options: ["5 seconds", "10 seconds", "30 seconds", "5 minutes"], correctIndex: 2, rationale: "Research supports 30-second static stretch holds for optimal flexibility gains. Stretches should be performed 3-5 times per session, multiple times daily for best results.", difficulty: 1, category: "Therapeutic Exercises", topic: "stretching parameters" },
  { id: "ota-1129", stem: "Which nerve gliding exercise is appropriate for median nerve mobilization at the wrist?", options: ["Ulnar nerve glide", "Median nerve glide through wrist extension and finger extension positions", "Radial nerve glide", "Spinal nerve stretch"], correctIndex: 1, rationale: "Median nerve glides use progressive positions of wrist extension, finger extension, forearm supination, and elbow extension to mobilize the median nerve through the carpal tunnel.", difficulty: 2, category: "Therapeutic Exercises", topic: "nerve gliding" },
  { id: "ota-1130", stem: "A client with poor hand coordination is performing pegboard activities. This targets which component?", options: ["Gross motor strength", "Fine motor dexterity and coordination", "Cardiovascular endurance", "Balance"], correctIndex: 1, rationale: "Pegboard activities target fine motor dexterity, precision, and coordination. They require pinch grasp, release accuracy, and visual-motor integration.", difficulty: 1, category: "Therapeutic Exercises", topic: "fine motor training" },
  { id: "ota-1131", stem: "What type of muscle contraction occurs when lowering a weight slowly (muscle lengthens under load)?", options: ["Concentric contraction", "Eccentric contraction", "Isometric contraction", "Passive movement"], correctIndex: 1, rationale: "Eccentric contraction occurs when the muscle lengthens under load (controlling the lowering of a weight). Eccentric exercise is important for functional strength and injury prevention.", difficulty: 1, category: "Therapeutic Exercises", topic: "muscle contraction types" },
  { id: "ota-1132", stem: "Which warm-up activity is most appropriate before upper extremity strengthening?", options: ["Maximum effort lift", "5-10 minutes of gentle AROM, light activity, or warm moist heat application", "Cold immersion", "Static stretching of 5 minutes per muscle group"], correctIndex: 1, rationale: "Warm-up increases blood flow, tissue temperature, and flexibility before strengthening. Gentle AROM, light functional activities, or moist heat prepare tissues for exercise.", difficulty: 1, category: "Therapeutic Exercises", topic: "exercise preparation" },
  { id: "ota-1133", stem: "A client post-tendon repair is beginning place-and-hold exercises. What does this involve?", options: ["Passively placing the finger in a flexed position, then actively holding that position", "Aggressive active movement through full range", "Complete immobilization", "Maximum resistance gripping"], correctIndex: 0, rationale: "Place-and-hold (also called modified Duran): the finger is passively placed in a flexed position, then the client actively maintains (holds) that position. This generates minimal tendon excursion force while promoting active muscle recruitment.", difficulty: 3, category: "Therapeutic Exercises", topic: "early active motion protocols" },
  { id: "ota-1134", stem: "Which exercise progression is correct for improving shoulder stability?", options: ["Weight-bearing exercises first, then ROM", "ROM → AROM → AAROM → strengthening → functional activities", "PROM → AAROM → AROM → isometric strengthening → isotonic strengthening → functional", "Plyometrics → ROM → strengthening"], correctIndex: 2, rationale: "Shoulder rehab progresses: PROM → AAROM → AROM → isometric → isotonic → functional. Each phase ensures adequate healing and motor control before increasing demands.", difficulty: 2, category: "Therapeutic Exercises", topic: "exercise progression principles" },
  { id: "ota-1135", stem: "A client needs to improve bilateral hand coordination. Which activity is MOST appropriate?", options: ["Single-hand pegboard tasks", "Bilateral tasks such as opening a jar, folding laundry, or playing a keyboard", "Unilateral weight lifting", "Passive ROM exercises"], correctIndex: 1, rationale: "Bilateral activities (opening jars, folding, typing) require coordinated use of both hands in complementary or symmetrical patterns, improving bilateral integration and coordination.", difficulty: 1, category: "Therapeutic Exercises", topic: "bilateral coordination" },
  { id: "ota-1136", stem: "What is the FITT principle in exercise prescription?", options: ["First, Intermediate, Tertiary, Total", "Frequency, Intensity, Time (duration), Type of exercise", "Focus, Improvement, Tolerance, Training", "Fast, Intense, Thorough, Targeted"], correctIndex: 1, rationale: "FITT: Frequency (how often), Intensity (how hard), Time (how long), Type (what kind of exercise). This framework guides individualized exercise prescription.", difficulty: 1, category: "Therapeutic Exercises", topic: "exercise prescription" },
  { id: "ota-1137", stem: "A client with wrist drop from radial nerve palsy should perform which exercise?", options: ["Wrist flexion strengthening", "Passive wrist extension with dynamic wrist extension splint, progressing to active-assisted extension as nerve recovers", "Only grip strengthening", "No exercise — wait for surgical intervention"], correctIndex: 1, rationale: "Radial nerve palsy requires maintaining wrist extension ROM via passive stretching and a dynamic wrist extension splint. As nerve recovery occurs, AAROM and AROM exercises progress.", difficulty: 2, category: "Therapeutic Exercises", topic: "nerve palsy exercise" },
  { id: "ota-1138", stem: "Which activity targets proximal upper extremity strengthening for a client with shoulder weakness?", options: ["Finger pinching activities", "Reaching overhead to place objects on shelves", "Wrist curl exercises only", "Handwriting practice"], correctIndex: 1, rationale: "Reaching overhead targets proximal shoulder muscles (deltoid, rotator cuff, scapular stabilizers) through antigravity functional movement. Progress from table-height to overhead activities.", difficulty: 1, category: "Therapeutic Exercises", topic: "functional strengthening" },
  { id: "ota-1139", stem: "A client is performing scapular stabilization exercises. Which muscle is the primary scapular stabilizer being targeted?", options: ["Biceps", "Serratus anterior", "Brachioradialis", "Wrist extensors"], correctIndex: 1, rationale: "The serratus anterior is the primary scapular stabilizer, protracting and upwardly rotating the scapula. Weakness causes scapular winging and impaired shoulder function.", difficulty: 2, category: "Therapeutic Exercises", topic: "scapular stabilization" },
  { id: "ota-1140", stem: "What is the primary benefit of using resistance bands for upper extremity strengthening?", options: ["They are more expensive than weights", "They provide variable resistance throughout the range and are portable and gradable by color/resistance level", "They only work for lower extremity", "They cannot be graded"], correctIndex: 1, rationale: "Resistance bands are portable, color-coded by resistance level, and provide variable resistance (increasing with stretch). They allow graded exercise in multiple planes of movement.", difficulty: 1, category: "Therapeutic Exercises", topic: "therapeutic equipment" },
  { id: "ota-1141", stem: "A client with decreased finger dexterity after hand surgery should practice which functional activity?", options: ["Heavy lifting", "Buttoning, zipping, picking up small objects, and coin manipulation", "Only gross motor activities", "Running and jumping"], correctIndex: 1, rationale: "Fine motor dexterity activities (buttoning, zipping, coin manipulation, bead stringing) challenge precision, in-hand manipulation, and controlled finger movements needed for ADL independence.", difficulty: 1, category: "Therapeutic Exercises", topic: "functional dexterity training" },
  { id: "ota-1142", stem: "Which cooling technique should be applied AFTER exercise to manage inflammation?", options: ["Moist heat pack", "Cryotherapy (ice application for 15-20 minutes)", "Warm bath", "Hot paraffin"], correctIndex: 1, rationale: "Cryotherapy after exercise reduces inflammation, edema, and pain through vasoconstriction. Apply ice wrapped in towel for 15-20 minutes. Contrast with heat used BEFORE exercise to improve tissue extensibility.", difficulty: 1, category: "Therapeutic Exercises", topic: "modalities with exercise" },
  { id: "ota-1143", stem: "A client demonstrates difficulty with in-hand manipulation. Which activity best addresses this deficit?", options: ["Gross grasp of large objects", "Rotating coins between fingertips (finger-to-palm and palm-to-finger translation)", "Passive finger stretching", "Wrist strengthening"], correctIndex: 1, rationale: "In-hand manipulation includes translation (moving objects palm-to-finger), rotation (turning objects), and shift (adjusting grip). Coin manipulation challenges all three components.", difficulty: 2, category: "Therapeutic Exercises", topic: "in-hand manipulation" },
  { id: "ota-1144", stem: "What is the recommended rest interval between sets of strengthening exercises for muscle recovery?", options: ["No rest needed", "30-120 seconds between sets", "5 minutes between each repetition", "24 hours between sets"], correctIndex: 1, rationale: "30-120 seconds rest between sets allows metabolic recovery while maintaining training stimulus. Shorter rest (30-60s) for endurance; longer rest (60-120s) for strength.", difficulty: 1, category: "Therapeutic Exercises", topic: "exercise parameters" },
  { id: "ota-1145", stem: "A client is using a Baltimore Therapeutic Equipment (BTE) work simulator. What does this device assess?", options: ["Cognitive function", "Simulated work tasks with measurable force, endurance, and functional capacity", "Cardiac function", "Vision"], correctIndex: 1, rationale: "BTE work simulators replicate real work tasks (turning, lifting, gripping) while measuring force output, endurance, and functional capacity for return-to-work assessment and training.", difficulty: 2, category: "Therapeutic Exercises", topic: "work simulation" },
  { id: "ota-1146", stem: "Which exercise is contraindicated for a client with a recent finger extensor tendon repair over the PIP joint?", options: ["Passive PIP extension", "Forceful active PIP flexion", "Gentle AROM in protected splint", "Place-and-hold extension exercises"], correctIndex: 1, rationale: "Forceful active PIP flexion generates high tensile load on the healing extensor tendon at the PIP, risking rupture. Controlled motion protocols protect the repair.", difficulty: 3, category: "Therapeutic Exercises", topic: "tendon repair precautions" },
  { id: "ota-1147", stem: "A client needs to improve pinch strength. Which activity provides graded resistance for tip pinch?", options: ["Squeezing a tennis ball", "Picking up progressively smaller and heavier objects using tip-to-tip pinch", "Gross grasp of a cylindrical object", "Passive thumb ROM"], correctIndex: 1, rationale: "Tip pinch strengthening uses graded objects requiring thumb-to-fingertip opposition. Progress from larger, lighter objects to smaller, heavier ones to increase demand on thenar muscles.", difficulty: 1, category: "Therapeutic Exercises", topic: "pinch strengthening" },
  { id: "ota-1148", stem: "What is the primary indication for using a continuous passive motion (CPM) machine after surgery?", options: ["To strengthen muscles", "To maintain joint ROM and promote healing by preventing adhesions during early post-operative phase", "To increase cardiovascular endurance", "To improve balance"], correctIndex: 1, rationale: "CPM machines provide passive joint movement to maintain ROM, promote cartilage healing, prevent adhesions, and reduce stiffness in the early post-operative phase when active motion may be limited.", difficulty: 2, category: "Therapeutic Exercises", topic: "post-operative modalities" },
  { id: "ota-1149", stem: "A client with poor proprioception in the hand should perform which exercise?", options: ["Visual gaze exercises", "Eyes-closed object manipulation, texture identification, and joint position sense activities", "Cardiovascular training", "Lower extremity exercises"], correctIndex: 1, rationale: "Proprioceptive retraining uses eyes-closed activities: identifying objects by touch, recognizing finger positions, texture discrimination, and weight estimation to challenge and rebuild proprioceptive awareness.", difficulty: 2, category: "Therapeutic Exercises", topic: "proprioceptive training" },
  { id: "ota-1150", stem: "Which functional activity combines upper extremity strength, coordination, and cognitive sequencing?", options: ["Passive arm movement by therapist", "Cooking a simple meal (reaching, stirring, measuring, sequencing steps)", "Lying in bed", "Listening to music"], correctIndex: 1, rationale: "Cooking combines UE strength (reaching, lifting), coordination (stirring, cutting), fine motor skills (measuring), and cognitive sequencing (following recipe steps) into a meaningful occupation.", difficulty: 1, category: "Therapeutic Exercises", topic: "functional task training" },
  { id: "ota-1151", stem: "A client is performing wrist circumduction exercises. What motion does this involve?", options: ["Up and down only", "Side to side only", "Circular motion combining flexion, extension, radial deviation, and ulnar deviation", "Rotation only"], correctIndex: 2, rationale: "Circumduction is a circular motion combining flexion, extension, radial deviation, and ulnar deviation in sequence. It promotes comprehensive wrist mobility and tendon gliding.", difficulty: 1, category: "Therapeutic Exercises", topic: "wrist mobility" },
  { id: "ota-1152", stem: "What is the primary goal of weight-bearing exercises through the affected upper extremity post-stroke?", options: ["To increase spasticity", "To provide proprioceptive input, normalize tone, and promote weight acceptance through the hemiplegic arm", "To cause pain in the shoulder", "To stretch the biceps"], correctIndex: 1, rationale: "Weight-bearing through the hemiplegic UE provides proprioceptive input, helps normalize muscle tone (reduces spasticity through prolonged stretch), and promotes motor activation.", difficulty: 2, category: "Therapeutic Exercises", topic: "neurological exercise approaches" },
  { id: "ota-1153", stem: "A client recovering from a hand burn needs to maintain finger web space. Which exercise is appropriate?", options: ["Sustained fist making", "Finger spreading (abduction) exercises and web space stretching with conformer splints", "Keeping fingers tightly together at all times", "No hand exercises during healing"], correctIndex: 1, rationale: "Burn scars can contracture web spaces. Finger abduction exercises and web spacer conformers maintain web space width. Anti-deformity positioning opposes the expected contracture direction.", difficulty: 2, category: "Therapeutic Exercises", topic: "burn exercise" },
  { id: "ota-1154", stem: "Which exercise principle states that muscles must be challenged beyond their current capacity to improve?", options: ["Specificity principle", "Overload principle", "Reversibility principle", "Diminishing returns principle"], correctIndex: 1, rationale: "The overload principle states muscles must be subjected to loads greater than normally encountered to stimulate strength gains. Progressive overload gradually increases resistance.", difficulty: 1, category: "Therapeutic Exercises", topic: "exercise principles" },
  { id: "ota-1155", stem: "A client with edema in the hand should perform which exercise to promote fluid reduction?", options: ["Vigorous grip strengthening", "Elevation combined with gentle active finger pumping (fist making and opening)", "Immobilization of the hand", "Hot pack application"], correctIndex: 1, rationale: "Active finger pumping with the hand elevated uses the muscle pump effect to promote venous and lymphatic return, reducing edema. Combine with retrograde massage and compression.", difficulty: 1, category: "Therapeutic Exercises", topic: "edema exercise" },
  { id: "ota-1156", stem: "What is the typical exercise prescription for strengthening using the DeLorme PRE method?", options: ["1 set of maximum weight", "3 sets of 10 repetitions at 50%, 75%, and 100% of 10RM (ascending)", "5 sets of 50 reps at light weight", "Random sets and reps"], correctIndex: 1, rationale: "DeLorme PRE: Set 1 = 10 reps at 50% 10RM, Set 2 = 10 reps at 75% 10RM, Set 3 = 10 reps at 100% 10RM. This progressive ascending resistance method effectively builds strength.", difficulty: 2, category: "Therapeutic Exercises", topic: "strengthening protocols" },
  { id: "ota-1157", stem: "A client with shoulder impingement should avoid which exercise?", options: ["Pendulum exercises", "Exercises above 90° of flexion or abduction during the acute phase", "Scapular retraction exercises", "Gentle external rotation at the side"], correctIndex: 1, rationale: "During acute shoulder impingement, overhead movements compress the supraspinatus tendon under the acromion. Exercise should focus on scapular stabilization and rotator cuff strengthening below 90°.", difficulty: 2, category: "Therapeutic Exercises", topic: "shoulder impingement management" },
  { id: "ota-1158", stem: "Which hand exercise challenges the ability to isolate individual finger movements?", options: ["Gross grasp of a cylinder", "Finger isolation exercises: touching each finger to thumb individually in sequence", "Bilateral pushing activity", "Wrist flexion/extension only"], correctIndex: 1, rationale: "Finger-to-thumb opposition in sequence (index-middle-ring-small) challenges individual finger isolation, motor planning, and coordination. Speed and accuracy can be graded.", difficulty: 1, category: "Therapeutic Exercises", topic: "finger isolation" },
  { id: "ota-1159", stem: "A client post-ORIF of distal radius is 8 weeks post-surgery. Which exercise is now appropriate?", options: ["High-impact plyometric activities", "Progressive resistive exercises for wrist and grip strengthening", "Only passive ROM", "No exercise until 6 months"], correctIndex: 1, rationale: "At 8 weeks post-ORIF, bone healing is sufficient for progressive resistive exercise. Begin with light resistance and gradually increase based on tolerance and surgeon protocol.", difficulty: 2, category: "Therapeutic Exercises", topic: "post-surgical strengthening" },
  { id: "ota-1160", stem: "What is the purpose of blocking exercises for the hand?", options: ["To prevent all movement", "To isolate and strengthen specific finger joint movement by stabilizing adjacent joints", "To block blood flow", "To block pain"], correctIndex: 1, rationale: "Blocking exercises stabilize one joint (e.g., MCP) to isolate movement at another (e.g., PIP or DIP). FDS blocking targets PIP flexion; FDP blocking targets DIP flexion.", difficulty: 2, category: "Therapeutic Exercises", topic: "isolated joint exercises" },
  { id: "ota-1161", stem: "An OTA is teaching a client to use a button hook for dressing. This is an example of which type of assistive device?", options: ["High-technology device", "Low-technology adaptive device", "Prosthetic device", "Orthotic device"], correctIndex: 1, rationale: "A button hook is a simple, low-technology adaptive device that enables one-handed buttoning. It compensates for limited fine motor dexterity or unilateral hand function.", difficulty: 1, category: "Assistive Devices", topic: "adaptive equipment" },
  { id: "ota-1162", stem: "A client with limited grip strength has difficulty turning doorknobs. Which adaptation is MOST appropriate?", options: ["Replace all doors with automatic doors", "Install lever-style door handles", "Remove all doors", "Use door stops only"], correctIndex: 1, rationale: "Lever handles require a push-down motion rather than grip and rotation, accommodating clients with weak grip, arthritis, or hand deformities. This is a universal design principle.", difficulty: 1, category: "Assistive Devices", topic: "home modifications" },
  { id: "ota-1163", stem: "A client with C5 SCI needs to feed independently. Which equipment combination is needed?", options: ["Standard utensils only", "Universal cuff with built-up utensils and mobile arm support", "No equipment — direct hand feeding", "Only a plate guard"], correctIndex: 1, rationale: "C5 SCI preserves deltoid and biceps but lacks hand grasp. Universal cuff straps the utensil to the hand, mobile arm support positions the arm, and built-up utensils aid control.", difficulty: 2, category: "Assistive Devices", topic: "SCI adaptive equipment" },
  { id: "ota-1164", stem: "Which bathing device helps a client with limited balance safely enter and exit a bathtub?", options: ["Bath thermometer", "Tub transfer bench with grab bars", "Loofah sponge", "Shower cap"], correctIndex: 1, rationale: "A tub transfer bench spans the tub wall allowing seated entry/exit. Combined with grab bars, it provides safe bathing access for clients with balance, strength, or mobility limitations.", difficulty: 1, category: "Assistive Devices", topic: "bathing equipment" },
  { id: "ota-1165", stem: "A client with one-handed function needs to stabilize a cutting board while preparing food. Which device is recommended?", options: ["Regular cutting board", "Dycem non-slip mat and cutting board with suction cups and corner guards", "Wet towel under the board", "No cutting — pre-cut foods only"], correctIndex: 1, rationale: "A non-slip mat (Dycem) prevents sliding, and a cutting board with suction cups and corner guards/spikes stabilizes food for one-handed cutting. Rocker knives complement one-handed cutting.", difficulty: 1, category: "Assistive Devices", topic: "kitchen adaptations" },
  { id: "ota-1166", stem: "Which dressing aid allows a client with limited shoulder ROM to don a shirt without raising arms overhead?", options: ["Regular pull-over shirt", "Front-opening shirt with Velcro closures or button hooks", "Tight compression shirt", "Back-opening shirt"], correctIndex: 1, rationale: "Front-opening shirts with Velcro or magnetic closures eliminate the need for overhead arm raising. Button hooks assist with buttoning when hand function is limited.", difficulty: 1, category: "Assistive Devices", topic: "dressing aids" },
  { id: "ota-1167", stem: "A client with low vision needs assistance with medication management. Which assistive device would help?", options: ["Smaller pill bottles", "Talking pill organizer with large-print labels and audible reminders", "Regular prescription bottles", "Colored medications only"], correctIndex: 1, rationale: "Talking pill organizers provide audible reminders, large-print labels improve readability, and compartmentalized weekly organizers simplify medication management for low-vision clients.", difficulty: 1, category: "Assistive Devices", topic: "vision aids" },
  { id: "ota-1168", stem: "What is the primary purpose of a reacher/grabber device?", options: ["To exercise the arm", "To extend functional reach for retrieving objects from high shelves or the floor without bending or stretching", "To measure grip strength", "To style hair"], correctIndex: 1, rationale: "A reacher extends functional reach to retrieve objects without bending (hip precautions), stretching overhead, or stooping — maintaining safety while promoting independence.", difficulty: 1, category: "Assistive Devices", topic: "reaching aids" },
  { id: "ota-1169", stem: "A client with weak grasp needs to write. Which pen adaptation is most appropriate?", options: ["Thinner pen", "Built-up grip pen or ergonomic grip added to standard pen", "Stylus pen", "Mechanical pencil"], correctIndex: 1, rationale: "Built-up grips increase pen diameter, reducing the fine motor precision and grip force required for writing. Ergonomic grips distribute force and reduce hand fatigue.", difficulty: 1, category: "Assistive Devices", topic: "writing aids" },
  { id: "ota-1170", stem: "Which environmental control unit (ECU) allows a client with high-level SCI to operate home electronics?", options: ["Standard remote control", "Voice-activated or switch-operated ECU for lights, TV, phone, and door locks", "A helper must operate everything", "Manual switches only"], correctIndex: 1, rationale: "ECUs allow clients with limited motor function to control home electronics (lights, TV, climate, doors) via voice commands, switch access, or eye-gaze technology, promoting independence.", difficulty: 2, category: "Assistive Devices", topic: "environmental controls" },
  { id: "ota-1171", stem: "A client with rheumatoid arthritis has difficulty opening jars. Which device reduces joint stress?", options: ["Using more grip force", "Electric jar opener or under-counter jar gripper", "Hitting the jar on the counter", "Having someone else always open jars"], correctIndex: 1, rationale: "Electric jar openers and under-counter jar grippers reduce the grip force and torque required, protecting finger and wrist joints from excessive stress consistent with joint protection principles.", difficulty: 1, category: "Assistive Devices", topic: "joint protection devices" },
  { id: "ota-1172", stem: "Which type of splint allows movement in one direction while blocking unwanted motion?", options: ["Static splint", "Dynamic splint", "Static-progressive splint", "Serial static splint"], correctIndex: 1, rationale: "Dynamic splints allow controlled movement through springs, rubber bands, or elastic elements. They can assist weak motion or block unwanted motion while permitting desired movement.", difficulty: 2, category: "Assistive Devices", topic: "splint types" },
  { id: "ota-1173", stem: "A client with a below-elbow amputation is being fitted with a myoelectric prosthesis. How does it work?", options: ["Purely cosmetic — no movement", "Electrical signals from residual limb muscles control motorized hand/hook opening and closing", "Body-powered cable system", "Pneumatic pressure system"], correctIndex: 1, rationale: "Myoelectric prostheses use EMG signals detected by electrodes over residual limb muscles to control battery-powered motors that open and close the terminal device.", difficulty: 2, category: "Assistive Devices", topic: "prosthetics" },
  { id: "ota-1174", stem: "A client needs a device to maintain finger extension position at night after tendon surgery. Which device is appropriate?", options: ["Weighted cuff", "Static extension splint (resting hand splint in anti-deformity position)", "Resistance band", "Exercise putty"], correctIndex: 1, rationale: "A static extension splint maintains finger position during rest/sleep to prevent flexion contractures after extensor tendon surgery. It is worn at night and between exercise sessions.", difficulty: 1, category: "Assistive Devices", topic: "orthotic devices" },
  { id: "ota-1175", stem: "Which device helps a client with limited hand function use a standard computer?", options: ["Standard keyboard only", "Ergonomic keyboard, voice recognition software, or head-pointing mouse alternative", "Pen and paper only", "No computer access possible"], correctIndex: 1, rationale: "Computer access alternatives include ergonomic keyboards, voice recognition (Dragon), head/eye-pointing devices, switch-access scanning, and touchscreen adaptations for various levels of hand function.", difficulty: 1, category: "Assistive Devices", topic: "computer access" },
  { id: "ota-1176", stem: "A client needs a device to hold playing cards with one hand. Which adaptation is appropriate?", options: ["Rubber band around the cards", "Card holder device that displays cards in a fan arrangement", "Asking another player to hold them", "Using fewer cards"], correctIndex: 1, rationale: "A card holder holds multiple cards in a fan display, enabling one-handed card play. This promotes leisure participation for clients with unilateral hand function.", difficulty: 1, category: "Assistive Devices", topic: "leisure adaptations" },
  { id: "ota-1177", stem: "What is the primary purpose of a rocker knife?", options: ["To rock while eating", "To allow one-handed cutting by rocking the curved blade through food", "To carve meat at the table", "To cut paper"], correctIndex: 1, rationale: "A rocker knife has a curved blade that rocks back and forth to cut food with one hand, eliminating the need for a fork-and-knife bilateral technique.", difficulty: 1, category: "Assistive Devices", topic: "feeding aids" },
  { id: "ota-1178", stem: "Which adaptive device helps a client with hip precautions put on socks?", options: ["Elastic shoelaces", "Sock aid (rigid or flexible)", "Shoe horn only", "Compression stockings"], correctIndex: 1, rationale: "A sock aid is a rigid or flexible device that holds the sock open while the client slides their foot in, avoiding hip flexion beyond 90° required for reaching the feet.", difficulty: 1, category: "Assistive Devices", topic: "dressing aids" },
  { id: "ota-1179", stem: "A client with tremor has difficulty eating without spilling. Which utensil adaptation would help?", options: ["Lighter utensils", "Weighted utensils or self-stabilizing utensils (e.g., Liftware)", "Longer utensils", "Sharper utensils"], correctIndex: 1, rationale: "Weighted utensils dampen tremor through added mass. Self-stabilizing utensils (Liftware) use electronic stabilization to counteract tremor movements during feeding.", difficulty: 1, category: "Assistive Devices", topic: "tremor management devices" },
  { id: "ota-1180", stem: "Which device assists a client with weak hand function to turn a key in a lock?", options: ["Duplicate keys", "Key turner/key holder with built-up handle for leverage", "Keypad lock only", "Someone else to open locks"], correctIndex: 1, rationale: "A key turner adds a built-up handle to the key, providing mechanical leverage that reduces the grip strength and fine motor precision required for key turning.", difficulty: 1, category: "Assistive Devices", topic: "community access devices" },
  { id: "ota-1181", stem: "Before initiating any patient treatment, the OTA must verify which safety measure?", options: ["The room temperature", "Patient identification, allergies, precautions, and current orders", "The weather outside", "The therapist's schedule"], correctIndex: 1, rationale: "Verifying patient identification, checking allergies, reviewing precautions (fall risk, weight-bearing status, isolation), and confirming current orders are essential safety checks before treatment.", difficulty: 1, category: "Patient Safety", topic: "pre-treatment safety" },
  { id: "ota-1182", stem: "A client is at high risk for falls. Which environmental modification is the HIGHEST priority?", options: ["New paint colors", "Removing throw rugs, improving lighting, and installing grab bars in bathroom", "New furniture", "Better window coverings"], correctIndex: 1, rationale: "Fall prevention priorities: remove trip hazards (throw rugs, clutter), improve lighting (nightlights, hallway lights), and install grab bars near toilet and tub/shower.", difficulty: 1, category: "Patient Safety", topic: "fall prevention" },
  { id: "ota-1183", stem: "An OTA notices a client's skin breaking down under a splint. What is the FIRST action?", options: ["Continue splint use and monitor", "Remove the splint immediately, assess skin, and report to supervising OT for splint modification", "Apply more padding and continue", "Document and wait until next visit"], correctIndex: 1, rationale: "Skin breakdown under a splint requires immediate removal, skin assessment, and OT notification. The splint needs modification (padding, pressure relief, design change) before reapplication.", difficulty: 1, category: "Patient Safety", topic: "splint safety" },
  { id: "ota-1184", stem: "During a transfer, the client begins to fall. What should the OTA do?", options: ["Try to catch the client and lift them back up", "Control the descent to the floor, protect the client's head, lower gently to the nearest safe surface", "Let go and step back", "Call for help only"], correctIndex: 1, rationale: "Never try to fully catch a falling client — this risks injury to both parties. Control the descent by guiding the client gently to the floor, protecting the head and key body parts.", difficulty: 1, category: "Patient Safety", topic: "fall management" },
  { id: "ota-1185", stem: "A client with diabetes has decreased sensation in the feet. Which safety education is essential?", options: ["Walk barefoot for better traction", "Check feet daily for cuts/sores, wear proper footwear, test water temperature with hands before bathing", "Ignore minor wounds", "Apply heat to feet daily"], correctIndex: 1, rationale: "Diabetic neuropathy reduces protective sensation. Daily foot inspection, proper footwear, testing water temperature with intact-sensation body parts, and prompt wound care prevent complications.", difficulty: 1, category: "Patient Safety", topic: "diabetic safety" },
  { id: "ota-1186", stem: "Which safety precaution should the OTA follow when using hot packs as a preparatory modality?", options: ["Apply directly to skin", "Wrap in 6-8 layers of toweling and check skin after 5 minutes; total application 15-20 minutes", "Leave on indefinitely", "Apply to insensate areas without checking"], correctIndex: 1, rationale: "Hot packs are wrapped in 6-8 layers of toweling to prevent burns. Check skin after 5 minutes for excessive redness. Never apply to insensate areas, over tumors, or over recent fractures.", difficulty: 1, category: "Patient Safety", topic: "thermal modality safety" },
  { id: "ota-1187", stem: "A client on blood thinners (anticoagulants) requires special precautions during therapy. Which is correct?", options: ["Aggressive joint mobilization is safe", "Avoid aggressive techniques; monitor for bruising, bleeding, and report unusual bruising to medical team", "Apply deep tissue massage without concern", "Blood thinners have no effect on therapy"], correctIndex: 1, rationale: "Anticoagulants increase bleeding risk. The OTA should avoid aggressive ROM, deep pressure, and sharp debridement. Monitor for unusual bruising and report promptly.", difficulty: 2, category: "Patient Safety", topic: "medication precautions" },
  { id: "ota-1188", stem: "What is the FIRST step when a client complains of chest pain during therapy?", options: ["Continue the activity at a slower pace", "Stop the activity immediately, have the client sit or lie down, and notify medical team/call emergency services", "Increase exercise intensity to work through the pain", "Document the complaint and continue"], correctIndex: 1, rationale: "Chest pain during activity could indicate cardiac emergency. Stop immediately, position the client comfortably, monitor vital signs, and activate emergency response.", difficulty: 1, category: "Patient Safety", topic: "medical emergencies" },
  { id: "ota-1189", stem: "A client with epilepsy has a seizure during therapy. What should the OTA do?", options: ["Restrain the client and insert something in their mouth", "Protect the client from injury (clear area, cushion head), time the seizure, do not restrain, turn to side after convulsions stop", "Continue therapy during the seizure", "Leave the room immediately"], correctIndex: 1, rationale: "During a seizure: clear hazards, cushion the head, time the duration, do not restrain or insert objects in the mouth. After: turn to recovery position, monitor breathing, report to medical team.", difficulty: 1, category: "Patient Safety", topic: "seizure management" },
  { id: "ota-1190", stem: "Which safety measure prevents the spread of infection when working with multiple clients?", options: ["Using the same gloves for all clients", "Hand hygiene between every client contact using soap/water or alcohol-based hand rub", "Wearing the same gown all day", "Only washing hands at the end of the day"], correctIndex: 1, rationale: "Hand hygiene between every client is the single most important infection prevention measure. Alcohol-based hand rubs are acceptable unless hands are visibly soiled.", difficulty: 1, category: "Patient Safety", topic: "infection control" },
  { id: "ota-1191", stem: "A client has a known latex allergy. What should the OTA do before treatment?", options: ["Use standard latex gloves anyway", "Use non-latex gloves and ensure all equipment is latex-free", "Ignore the allergy information", "Only use latex gloves briefly"], correctIndex: 1, rationale: "Latex allergies can cause anaphylaxis. Use non-latex alternatives (nitrile gloves, non-latex resistance bands) and verify all equipment is latex-free before treatment.", difficulty: 1, category: "Patient Safety", topic: "allergy precautions" },
  { id: "ota-1192", stem: "What is the proper way to position the gait belt on a client during a transfer?", options: ["Around the neck", "Around the waist, snug over clothing, with the buckle at the front or side", "Around the ankles", "Around the chest"], correctIndex: 1, rationale: "The gait belt is placed around the waist over clothing, snug but not tight (two fingers should fit underneath). Buckle at front or side, grasped from underneath with palms up.", difficulty: 1, category: "Patient Safety", topic: "safe handling" },
  { id: "ota-1193", stem: "Which blood pressure reading should cause the OTA to STOP exercise and notify the physician?", options: ["120/80 mmHg", "Systolic >200 mmHg or diastolic >110 mmHg", "110/70 mmHg", "130/85 mmHg"], correctIndex: 1, rationale: "Exercise should be stopped if SBP exceeds 200 mmHg or DBP exceeds 110 mmHg (or per facility protocol). These values indicate dangerous hypertensive response requiring medical evaluation.", difficulty: 2, category: "Patient Safety", topic: "vital sign monitoring" },
  { id: "ota-1194", stem: "A client with a pacemaker has which precaution during therapy?", options: ["No precautions needed", "Avoid electromagnetic interference sources (diathermy, certain modalities) and monitor heart rate", "All exercise is contraindicated", "Only passive ROM is allowed"], correctIndex: 1, rationale: "Pacemaker precautions include avoiding shortwave/microwave diathermy, therapeutic ultrasound near the device, and monitoring heart rate (which may not exceed programmed limits).", difficulty: 2, category: "Patient Safety", topic: "cardiac device precautions" },
  { id: "ota-1195", stem: "What should the OTA do if a client reports feeling dizzy upon standing from a wheelchair?", options: ["Ignore the complaint", "Have the client sit back down immediately, monitor vital signs, and suspect orthostatic hypotension", "Tell the client to walk it off", "Continue standing activities"], correctIndex: 1, rationale: "Dizziness upon standing suggests orthostatic hypotension (blood pressure drop with position change). Sit the client down, monitor BP/HR, allow gradual position changes, and report to medical team.", difficulty: 1, category: "Patient Safety", topic: "orthostatic hypotension" },
  { id: "ota-1196", stem: "Which standard precaution requires the OTA to treat ALL bodily fluids as potentially infectious?", options: ["Contact precautions", "Universal/Standard precautions", "Droplet precautions", "Airborne precautions"], correctIndex: 1, rationale: "Standard (universal) precautions treat all blood and body fluids as potentially infectious regardless of known diagnosis. This includes hand hygiene, PPE, and safe sharps handling.", difficulty: 1, category: "Infection Prevention", topic: "standard precautions" },
  { id: "ota-1197", stem: "When should the OTA perform hand hygiene?", options: ["Only at the start of the day", "Before and after each patient contact, after removing gloves, and after touching contaminated surfaces", "Only after using the restroom", "Once per hour"], correctIndex: 1, rationale: "Hand hygiene timing: before patient contact, after patient contact, after removing gloves, after contact with body fluids/contaminated items, before aseptic procedures.", difficulty: 1, category: "Infection Prevention", topic: "hand hygiene" },
  { id: "ota-1198", stem: "A client is on contact precautions for MRSA. What PPE must the OTA wear?", options: ["No special precautions", "Gloves and gown upon entry to the room", "N95 mask only", "Only gloves"], correctIndex: 1, rationale: "Contact precautions for MRSA require gloves and gown upon room entry. Equipment should be dedicated to the client or disinfected between uses. Hand hygiene upon exit.", difficulty: 1, category: "Infection Prevention", topic: "contact precautions" },
  { id: "ota-1199", stem: "Which type of isolation precaution requires an N95 respirator mask?", options: ["Contact precautions", "Droplet precautions", "Airborne precautions (TB, measles, varicella)", "Standard precautions only"], correctIndex: 2, rationale: "Airborne precautions (tuberculosis, measles, varicella) require N95 respirator masks because these pathogens travel in small droplet nuclei that remain suspended in air.", difficulty: 1, category: "Infection Prevention", topic: "airborne precautions" },
  { id: "ota-1200", stem: "How should therapy equipment (e.g., therapy putty, resistance bands) be cleaned between clients?", options: ["Not necessary to clean", "Disinfect with facility-approved disinfectant wipes/solution between each client use", "Clean weekly only", "Replace after each client"], correctIndex: 1, rationale: "Shared therapy equipment must be disinfected between each client use with facility-approved disinfectant. Single-client items (putty) should not be shared.", difficulty: 1, category: "Infection Prevention", topic: "equipment disinfection" },
  { id: "ota-1201", stem: "An OTA accidentally sustains a needlestick injury. What is the correct immediate action?", options: ["Ignore it", "Wash the wound immediately with soap and water, report the incident, and follow facility exposure protocol", "Apply a bandage and continue working", "Wait until the end of the shift to report"], correctIndex: 1, rationale: "Needlestick protocol: immediately wash with soap and water (or flush mucous membranes), report to supervisor, complete incident report, and follow facility bloodborne pathogen exposure protocol.", difficulty: 1, category: "Infection Prevention", topic: "exposure management" },
  { id: "ota-1202", stem: "A client is on droplet precautions for influenza. What PPE does the OTA need?", options: ["N95 mask", "Surgical mask within 3-6 feet of the client", "No mask needed", "Full face shield only"], correctIndex: 1, rationale: "Droplet precautions require a surgical mask when within 3-6 feet of the patient. Droplets are larger particles that fall quickly and don't require N95 protection.", difficulty: 1, category: "Infection Prevention", topic: "droplet precautions" },
  { id: "ota-1203", stem: "Which cleaning method is appropriate for splints and orthotic devices used by a single client?", options: ["Autoclave after each use", "Clean with mild soap and water, allowing to air dry completely", "No cleaning needed", "Soak in bleach solution"], correctIndex: 1, rationale: "Client-specific splints are cleaned with mild soap and water and air dried. This maintains material integrity while preventing bacterial growth. Avoid harsh chemicals that may degrade thermoplastic.", difficulty: 1, category: "Infection Prevention", topic: "device maintenance" },
  { id: "ota-1204", stem: "What is the proper sequence for donning PPE?", options: ["Mask → gloves → gown → goggles", "Gown → mask/respirator → goggles/face shield → gloves", "Gloves → gown → mask → goggles", "Any order is acceptable"], correctIndex: 1, rationale: "Donning order: gown first, then mask/respirator, then eye protection (goggles/face shield), then gloves last. Doffing is reverse: gloves, goggles, gown, mask.", difficulty: 1, category: "Infection Prevention", topic: "PPE sequence" },
  { id: "ota-1205", stem: "An OTA is working with a client who has active shingles (herpes zoster). What precaution is needed?", options: ["No precautions", "Contact precautions with airborne precautions if disseminated; avoid contact with lesions", "Droplet precautions only", "Standard precautions only are sufficient"], correctIndex: 2, rationale: "Localized shingles requires contact precautions (avoid direct contact with lesions). Disseminated shingles requires airborne AND contact precautions. Non-immune staff should avoid caring for these clients.", difficulty: 2, category: "Infection Prevention", topic: "herpes zoster precautions" },
  { id: "ota-1206", stem: "What is the minimum duration for effective handwashing with soap and water?", options: ["5 seconds", "20 seconds", "2 minutes", "30 seconds"], correctIndex: 1, rationale: "CDC recommends handwashing with soap and water for at least 20 seconds (singing 'Happy Birthday' twice). Include all surfaces: palms, backs, between fingers, under nails, and wrists.", difficulty: 1, category: "Infection Prevention", topic: "hand hygiene technique" },
  { id: "ota-1207", stem: "Which Clostridium difficile (C. diff) precaution is unique compared to other contact precautions?", options: ["N95 mask required", "Soap and water handwashing required — alcohol-based hand rubs are NOT effective against C. diff spores", "No special precautions", "Only droplet precautions needed"], correctIndex: 1, rationale: "C. diff spores are resistant to alcohol-based hand sanitizers. Soap and water handwashing is required to physically remove spores. Bleach-based environmental cleaning is also necessary.", difficulty: 2, category: "Infection Prevention", topic: "C. diff management" },
  { id: "ota-1208", stem: "When should gloves be changed during patient care?", options: ["Only when visibly soiled", "Between dirty and clean tasks on the same patient, and between every patient", "At the end of the shift only", "Once per hour"], correctIndex: 1, rationale: "Gloves are changed between dirty and clean body sites on the same patient (e.g., after perineal care before wound care) and between every patient contact. Hand hygiene after removal.", difficulty: 1, category: "Infection Prevention", topic: "glove use" },
  { id: "ota-1209", stem: "What should the OTA do with therapy equipment that cannot be adequately disinfected between clients?", options: ["Use it anyway", "Designate it for single-client use or dispose of it", "Share between clients without cleaning", "Rinse with water only"], correctIndex: 1, rationale: "Equipment that cannot be adequately disinfected (certain porous materials, therapy putty) should be designated single-client items or disposed of to prevent cross-contamination.", difficulty: 1, category: "Infection Prevention", topic: "equipment management" },
  { id: "ota-1210", stem: "A client has a wound with purulent drainage. Which additional precaution beyond standard precautions may be needed?", options: ["No additional precautions", "Contact precautions with wound-specific culture results guiding additional measures", "Airborne precautions", "Only visual inspection"], correctIndex: 1, rationale: "Purulent wound drainage may contain resistant organisms. Contact precautions (gown, gloves) are indicated. Culture results guide specific antimicrobial precautions.", difficulty: 2, category: "Infection Prevention", topic: "wound precautions" },
  { id: "ota-1211", stem: "In occupational therapy documentation, which statement is an example of an objective measurement?", options: ["The client feels better today", "The client demonstrated 45° active shoulder flexion measured with goniometer", "The client seems motivated", "The family thinks the client is improving"], correctIndex: 1, rationale: "Objective documentation uses measurable data: specific ROM (45° with goniometer), timed assessments, standardized test scores, and observable functional performance.", difficulty: 1, category: "Documentation", topic: "objective documentation" },
  { id: "ota-1212", stem: "What is the purpose of writing functional goals in OT documentation?", options: ["To satisfy insurance requirements only", "To describe measurable, achievable outcomes that relate to the client's ability to perform meaningful occupations", "To record medical diagnoses", "To list exercises performed"], correctIndex: 1, rationale: "Functional goals describe what the client will DO in real-life terms (e.g., 'Client will independently don upper body garments within 5 minutes'). They must be measurable, achievable, and occupation-based.", difficulty: 1, category: "Documentation", topic: "goal writing" },
  { id: "ota-1213", stem: "Which documentation format organizes information as Subjective, Objective, Assessment, and Plan?", options: ["DAP note", "SOAP note", "Narrative note", "Checklist"], correctIndex: 1, rationale: "SOAP notes organize clinical documentation: S (client's report), O (measurable observations and data), A (clinical reasoning and analysis), P (future interventions and plan).", difficulty: 1, category: "Documentation", topic: "documentation formats" },
  { id: "ota-1214", stem: "An OTA makes an error in clinical documentation. What is the correct procedure?", options: ["Use white-out to cover the error", "Draw a single line through the error, write 'error,' initial, date, and write the correction", "Rewrite the entire note", "Ignore the error"], correctIndex: 1, rationale: "Documentation errors are corrected with a single line through the error, 'error' notation, initials, date, and the correction. Never use white-out, erase, or obliterate original entries.", difficulty: 1, category: "Documentation", topic: "error correction" },
  { id: "ota-1215", stem: "Which component is required in a well-written functional goal?", options: ["Only the client's name", "ABCD: Audience (client), Behavior (action), Condition (circumstances), Degree (criteria)", "Only the date", "Only the diagnosis"], correctIndex: 1, rationale: "Functional goals use ABCD format: Audience (who), Behavior (observable action), Condition (under what circumstances), Degree (to what measurable standard/criterion).", difficulty: 1, category: "Documentation", topic: "SMART goals" },
  { id: "ota-1216", stem: "What is the difference between a progress note and a discharge summary?", options: ["They are the same document", "Progress notes document ongoing treatment sessions; discharge summaries document outcomes and recommendations at termination of services", "Progress notes are written by physicians only", "Discharge summaries are optional"], correctIndex: 1, rationale: "Progress notes document individual treatment sessions (interventions, client response, progress toward goals). Discharge summaries document overall outcomes, goal achievement, and post-discharge recommendations.", difficulty: 1, category: "Documentation", topic: "documentation types" },
  { id: "ota-1217", stem: "Which statement represents a properly written short-term goal?", options: ["The client will get better", "Within 2 weeks, the client will independently don a button-front shirt using a button hook in under 5 minutes", "The client will exercise more", "The client should try harder"], correctIndex: 1, rationale: "This goal is SMART: Specific (don button-front shirt), Measurable (independently, under 5 minutes), Achievable, Relevant (dressing independence), Time-bound (2 weeks).", difficulty: 1, category: "Documentation", topic: "goal writing examples" },
  { id: "ota-1218", stem: "What information must be included in every OT treatment session note?", options: ["Only the therapist's opinion", "Date, time, client identification, interventions provided, client response, and therapist signature", "Just the exercises performed", "Only the client's complaints"], correctIndex: 1, rationale: "Session notes must include: date/time, client identification, skilled interventions provided, client's response/performance, progress toward goals, plan, and therapist signature with credentials.", difficulty: 1, category: "Documentation", topic: "documentation requirements" },
  { id: "ota-1219", stem: "Which abbreviation is commonly used in OT documentation to indicate 'activities of daily living'?", options: ["ROM", "ADL", "PRE", "CPM"], correctIndex: 1, rationale: "ADL = Activities of Daily Living. Common OT abbreviations: IADL (instrumental ADL), ROM (range of motion), MMT (manual muscle test), WFL (within functional limits), I (independent), A (assist).", difficulty: 1, category: "Documentation", topic: "clinical abbreviations" },
  { id: "ota-1220", stem: "Why is documenting the client's response to treatment important?", options: ["It is not important", "It demonstrates skilled service, justifies continued treatment, and tracks progress toward goals", "It is only needed for legal purposes", "It is optional information"], correctIndex: 1, rationale: "Client response documentation demonstrates the skilled nature of services, justifies medical necessity for continued treatment, tracks progress, and informs treatment modifications.", difficulty: 1, category: "Documentation", topic: "clinical reasoning documentation" },
  { id: "ota-1221", stem: "The OTA wants to document that a client performed a task with minimal verbal cues. Which assist level does this represent?", options: ["Independent", "Supervision (standby assist)", "Modified independent with verbal cues", "Maximum assist"], correctIndex: 2, rationale: "Modified independence with verbal cues indicates the client performs the task but needs occasional verbal reminders or cues. This is between supervision and independent on the assist scale.", difficulty: 1, category: "Documentation", topic: "assist levels" },
  { id: "ota-1222", stem: "What is the purpose of an OT re-evaluation?", options: ["To discharge the client", "To assess progress, update goals, and modify the treatment plan based on current functional status", "To diagnose new conditions", "To bill additional services"], correctIndex: 1, rationale: "Re-evaluation assesses progress toward goals, identifies new problems, updates measurable data, and guides treatment plan modifications. It is typically performed by the OT.", difficulty: 1, category: "Documentation", topic: "re-evaluation" },
  { id: "ota-1223", stem: "Which documentation practice helps protect against malpractice claims?", options: ["Minimal documentation", "Thorough, accurate, timely documentation of all assessments, interventions, client response, and communications", "Waiting a week to write notes", "Documenting only positive outcomes"], correctIndex: 1, rationale: "Thorough, timely, accurate documentation protects against malpractice by creating a legal record of care provided, clinical reasoning, client response, and communications.", difficulty: 1, category: "Documentation", topic: "legal documentation" },
  { id: "ota-1224", stem: "When documenting functional performance, which statement is MOST specific?", options: ["The client did well with dressing", "Client donned a pullover shirt independently in 3 minutes using compensatory one-handed technique", "The client practiced dressing", "Dressing was addressed in today's session"], correctIndex: 1, rationale: "Specific documentation includes the exact activity, level of independence, time to complete, and technique used. Vague statements like 'did well' lack measurable data.", difficulty: 1, category: "Documentation", topic: "specific documentation" },
  { id: "ota-1225", stem: "What is the difference between an initial evaluation and a screening in OT?", options: ["They are the same", "A screening identifies potential need for OT; an evaluation is a comprehensive assessment establishing the treatment plan", "Screenings are longer than evaluations", "OTAs perform initial evaluations"], correctIndex: 1, rationale: "Screening is a brief process to identify if OT services may be beneficial. Evaluation is a comprehensive assessment by the OT establishing diagnosis, prognosis, and treatment plan.", difficulty: 1, category: "Documentation", topic: "evaluation vs screening" },
  { id: "ota-1226", stem: "HIPAA regulations require the OTA to protect client health information. Which action violates HIPAA?", options: ["Discussing client information only with the treatment team", "Sharing client information on personal social media or discussing in public areas", "Securing paper records in locked files", "Using encrypted electronic health records"], correctIndex: 1, rationale: "HIPAA prohibits sharing protected health information (PHI) with unauthorized persons, on social media, or in public areas where others may overhear. Violations carry severe penalties.", difficulty: 1, category: "Documentation", topic: "HIPAA compliance" },
  { id: "ota-1227", stem: "What is the correct assist level terminology when a client performs 75% or more of a task independently?", options: ["Maximum assistance", "Moderate assistance", "Minimum assistance", "Dependent"], correctIndex: 2, rationale: "Minimum assistance: client performs 75%+ of the task. Moderate assistance: 50-74%. Maximum assistance: 25-49%. Dependent: client performs less than 25%.", difficulty: 1, category: "Documentation", topic: "assist level definitions" },
  { id: "ota-1228", stem: "Which type of documentation describes the client's overall course of treatment from initial evaluation through discharge?", options: ["Daily treatment note", "Discharge summary", "Referral form", "Prescription"], correctIndex: 1, rationale: "A discharge summary provides a comprehensive overview of the client's course of treatment, including initial status, goals addressed, progress made, outcomes achieved, and post-discharge recommendations.", difficulty: 1, category: "Documentation", topic: "discharge documentation" },
  { id: "ota-1229", stem: "The OTA cosigns a student's documentation. What is the OTA's responsibility?", options: ["No responsibility — the student is responsible", "The OTA must review, verify accuracy, and is ultimately responsible for the content", "Only sign without reading", "Ask the student to cosign the OTA's notes"], correctIndex: 1, rationale: "When cosigning, the OTA assumes responsibility for the accuracy and completeness of the documentation. They must read and verify content before signing.", difficulty: 2, category: "Documentation", topic: "supervision and cosigning" },
  { id: "ota-1230", stem: "What is included in the 'Assessment' section of a SOAP note?", options: ["Only client complaints", "Clinical reasoning, interpretation of data, progress analysis, and professional judgment about the client's status", "Exercise descriptions", "Billing information"], correctIndex: 1, rationale: "The Assessment section contains the therapist's clinical reasoning: interpretation of subjective and objective data, progress toward goals, barriers to progress, and rationale for plan modifications.", difficulty: 1, category: "Documentation", topic: "SOAP note components" },
];
